public class BitOps {
    public static void main(String[] args) {
        int a = 0b1010;  // 10
        int b = 0b1100;  // 12
        System.out.println(a & b);   // AND
        System.out.println(a | b);   // OR
        System.out.println(a ^ b);   // XOR
        System.out.println(~a & 0xFF); // NOT (masked to 8 bits)
        System.out.println(a << 1);  // left shift
    }
}
